SELECT e.enrollment_id, e.user_id, e.course_id, e.enrollment_status, e.completion_rate, e.enrollment_dt, e.completion_dt, e.reg_dt, e.upd_dt, u.user_nm, c.course_nm FROM tb_enrollment e LEFT JOIN tb_user u ON e.user_id = u.user_id LEFT JOIN tb_course c ON e.course_id = c.course_id WHERE 1=1
AND e.user_id = #{userId}
AND e.course_id = #{courseId}
AND e.enrollment_status = #{enrollmentStatus}
ORDER BY e.enrollment_dt DESC

SELECT COUNT(*)
FROM tb_enrollment
WHERE 1=1

    AND user_id = #{userId}


    AND course_id = #{courseId}


    AND enrollment_status = #{enrollmentStatus}
